mapper.select:
SELECT
    eq.NAME 设备名称,
    eq.LEVEL 设备等级,
    eq.factory 生产厂家,
    org.NAME 所属游乐园,
    org.contact_name 设备联系人,
    org.contact_job 联系人职位
FROM
    enuo_equipment eq
        LEFT JOIN enuo_org org ON eq.org_id = org.id


        AND eq.NAME = #{equipmentName}


        AND eq.level = #{level}


        AND eq.factory = #{factory}


        AND org.NAME = #{orgName}


        AND org.contactName = #{contactName}


        AND org.contactJob = #{contactJob}
